function toSegments(path) {
  if (Array.isArray(path)) return path;
  if (typeof path !== 'string') return null;
  const s = path.trim();
  if (!s) return [];
  return s.split('.');
}

export default function getByPath(obj, path, fallback) {
  const segs = toSegments(path);
  if (!segs) return fallback;

  let cur = obj;

  for (let i = 0; i < segs.length; i++) {
    const seg = segs[i];

    if (cur === null || cur === undefined) {
      return fallback;
    }

    // allow numeric indexing when segment is number or numeric string
    const key = typeof seg === 'number' ? seg : seg;

    // Only treat as missing when key is not present
    if (typeof cur === 'object' || typeof cur === 'function') {
      if (!(key in cur)) return fallback;
      cur = cur[key];
    } else {
      return fallback;
    }
  }

  return cur;
}
